package com.example.saml.security;

import com.example.saml.config.SamlProperties;
import org.springframework.core.io.Resource;
import org.springframework.core.io.ResourceLoader;
import org.springframework.stereotype.Component;

import java.io.InputStream;
import java.security.KeyStore;
import java.security.PrivateKey;
import java.security.cert.X509Certificate;

@Component
public class SamlKeyManager {
    private final SamlProperties samlProperties;
    private final ResourceLoader resourceLoader;
    private KeyStore keyStore;

    public SamlKeyManager(SamlProperties samlProperties, ResourceLoader resourceLoader) {
        this.samlProperties = samlProperties;
        this.resourceLoader = resourceLoader;
        loadKeyStore();
    }

    private void loadKeyStore() {
        try {
            keyStore = KeyStore.getInstance("JKS");
            Resource resource = resourceLoader.getResource(samlProperties.getKeystore().getLocation());
            try (InputStream inputStream = resource.getInputStream()) {
                keyStore.load(inputStream, samlProperties.getKeystore().getPassword().toCharArray());
            }
        } catch (Exception e) {
            throw new RuntimeException("Failed to load keystore", e);
        }
    }

    public X509Certificate getCertificate() {
        try {
            return (X509Certificate) keyStore.getCertificate(samlProperties.getKeystore().getAlias());
        } catch (Exception e) {
            throw new RuntimeException("Failed to get certificate", e);
        }
    }

    public PrivateKey getPrivateKey() {
        try {
            return (PrivateKey) keyStore.getKey(
                samlProperties.getKeystore().getAlias(),
                samlProperties.getKeystore().getKeyPassword().toCharArray()
            );
        } catch (Exception e) {
            throw new RuntimeException("Failed to get private key", e);
        }
    }
}

