package com.example.saml.service;

import net.shibboleth.utilities.java.support.codec.Base64Support;
import net.shibboleth.utilities.java.support.xml.BasicParserPool;
import org.opensaml.core.xml.XMLObject;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.core.xml.io.Unmarshaller;
import org.opensaml.core.xml.io.UnmarshallerFactory;
import org.opensaml.saml.saml2.core.*;
import org.opensaml.security.credential.Credential;
import org.opensaml.security.credential.CredentialSupport;
import org.opensaml.xmlsec.signature.Signature;
import org.opensaml.xmlsec.signature.support.SignatureValidator;
import org.springframework.stereotype.Component;
import org.w3c.dom.Document;
import org.w3c.dom.Element;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.ByteArrayInputStream;
import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;

@Component
public class SamlResponseProcessor {
    private final BasicParserPool parserPool;

    public SamlResponseProcessor(BasicParserPool parserPool) {
        this.parserPool = parserPool;
    }

    public Response decodeResponse(String base64EncodedResponse) throws Exception {
        byte[] decodedBytes = Base64Support.decode(base64EncodedResponse);
        String decodedResponse = new String(decodedBytes, StandardCharsets.UTF_8);

        DocumentBuilderFactory documentBuilderFactory = DocumentBuilderFactory.newInstance();
        documentBuilderFactory.setNamespaceAware(true);
        DocumentBuilder docBuilder = documentBuilderFactory.newDocumentBuilder();

        Document document = docBuilder.parse(new ByteArrayInputStream(decodedResponse.getBytes(StandardCharsets.UTF_8)));
        Element element = document.getDocumentElement();

        UnmarshallerFactory unmarshallerFactory = XMLObjectProviderRegistrySupport.getUnmarshallerFactory();
        Unmarshaller unmarshaller = unmarshallerFactory.getUnmarshaller(element);
        XMLObject xmlObject = unmarshaller.unmarshall(element);

        return (Response) xmlObject;
    }

    public SamlAuthenticationResult processResponse(Response response, Credential validationCredential) throws Exception {
        validateResponseSignature(response, validationCredential);
        
        StatusCode statusCode = response.getStatus().getStatusCode();
        if (!StatusCode.SUCCESS.equals(statusCode.getValue())) {
            throw new RuntimeException("SAML Response status not successful: " + statusCode.getValue());
        }

        if (response.getAssertions().isEmpty()) {
            throw new RuntimeException("No assertions found in SAML Response");
        }

        Assertion assertion = response.getAssertions().get(0);
        validateAssertion(assertion, validationCredential);

        return extractAuthenticationResult(assertion);
    }

    private void validateResponseSignature(Response response, Credential credential) throws Exception {
        if (response.isSigned()) {
            Signature signature = response.getSignature();
            SignatureValidator.validate(signature, credential);
        }
    }

    private void validateAssertion(Assertion assertion, Credential credential) throws Exception {
        if (assertion.isSigned()) {
            Signature signature = assertion.getSignature();
            SignatureValidator.validate(signature, credential);
        }

        Conditions conditions = assertion.getConditions();
        if (conditions != null) {
            Instant now = Instant.now();
            if (conditions.getNotBefore() != null && now.isBefore(conditions.getNotBefore())) {
                throw new RuntimeException("Assertion not yet valid");
            }
            if (conditions.getNotOnOrAfter() != null && now.isAfter(conditions.getNotOnOrAfter())) {
                throw new RuntimeException("Assertion expired");
            }
        }

        if (assertion.getSubject() == null) {
            throw new RuntimeException("Assertion has no subject");
        }
    }

    private SamlAuthenticationResult extractAuthenticationResult(Assertion assertion) {
        SamlAuthenticationResult result = new SamlAuthenticationResult();

        Subject subject = assertion.getSubject();
        if (subject != null && subject.getNameID() != null) {
            result.setNameId(subject.getNameID().getValue());
            result.setNameIdFormat(subject.getNameID().getFormat());
        }

        List<AuthnStatement> authnStatements = assertion.getAuthnStatements();
        if (!authnStatements.isEmpty()) {
            AuthnStatement authnStatement = authnStatements.get(0);
            result.setSessionIndex(authnStatement.getSessionIndex());
            result.setAuthenticationInstant(authnStatement.getAuthnInstant());
        }

        List<AttributeStatement> attributeStatements = assertion.getAttributeStatements();
        for (AttributeStatement attributeStatement : attributeStatements) {
            for (Attribute attribute : attributeStatement.getAttributes()) {
                List<String> values = new ArrayList<>();
                for (XMLObject xmlObject : attribute.getAttributeValues()) {
                    values.add(xmlObject.getDOM().getTextContent());
                }
                result.addAttribute(attribute.getName(), values);
            }
        }

        return result;
    }
}

