package com.example.saml.service;

import java.time.Instant;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class SamlAuthenticationResult {
    private String nameId;
    private String nameIdFormat;
    private String sessionIndex;
    private Instant authenticationInstant;
    private Map<String, List<String>> attributes = new HashMap<>();

    public String getNameId() {
        return nameId;
    }

    public void setNameId(String nameId) {
        this.nameId = nameId;
    }

    public String getNameIdFormat() {
        return nameIdFormat;
    }

    public void setNameIdFormat(String nameIdFormat) {
        this.nameIdFormat = nameIdFormat;
    }

    public String getSessionIndex() {
        return sessionIndex;
    }

    public void setSessionIndex(String sessionIndex) {
        this.sessionIndex = sessionIndex;
    }

    public Instant getAuthenticationInstant() {
        return authenticationInstant;
    }

    public void setAuthenticationInstant(Instant authenticationInstant) {
        this.authenticationInstant = authenticationInstant;
    }

    public Map<String, List<String>> getAttributes() {
        return attributes;
    }

    public void setAttributes(Map<String, List<String>> attributes) {
        this.attributes = attributes;
    }

    public void addAttribute(String name, List<String> values) {
        this.attributes.put(name, values);
    }
}

