package com.example.saml.service;

import com.example.saml.config.SamlProperties;
import com.example.saml.security.SamlKeyManager;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.core.xml.io.Marshaller;
import org.opensaml.core.xml.io.MarshallingException;
import org.opensaml.saml.common.xml.SAMLConstants;
import org.opensaml.saml.saml2.metadata.*;
import org.opensaml.security.credential.Credential;
import org.opensaml.security.credential.CredentialSupport;
import org.opensaml.xmlsec.keyinfo.KeyInfoGenerator;
import org.opensaml.xmlsec.keyinfo.impl.X509KeyInfoGeneratorFactory;
import org.opensaml.xmlsec.signature.KeyInfo;
import org.springframework.stereotype.Component;
import org.w3c.dom.Element;

import javax.xml.namespace.QName;
import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.dom.DOMSource;
import javax.xml.transform.stream.StreamResult;
import java.io.StringWriter;
import java.time.Instant;
import java.time.temporal.ChronoUnit;

@Component
public class SamlMetadataGenerator {
    private final SamlProperties samlProperties;
    private final SamlKeyManager samlKeyManager;

    public SamlMetadataGenerator(SamlProperties samlProperties, SamlKeyManager samlKeyManager) {
        this.samlProperties = samlProperties;
        this.samlKeyManager = samlKeyManager;
    }

    public String generateMetadata() throws Exception {
        EntityDescriptor entityDescriptor = buildSAMLObject(EntityDescriptor.class, EntityDescriptor.DEFAULT_ELEMENT_NAME);
        entityDescriptor.setEntityID(samlProperties.getSp().getEntityId());
        entityDescriptor.setValidUntil(Instant.now().plus(365, ChronoUnit.DAYS));

        SPSSODescriptor spDescriptor = buildSAMLObject(SPSSODescriptor.class, SPSSODescriptor.DEFAULT_ELEMENT_NAME);
        spDescriptor.setAuthnRequestsSigned(true);
        spDescriptor.setWantAssertionsSigned(true);
        spDescriptor.addSupportedProtocol(SAMLConstants.SAML20P_NS);

        X509KeyInfoGeneratorFactory keyInfoGeneratorFactory = new X509KeyInfoGeneratorFactory();
        keyInfoGeneratorFactory.setEmitEntityCertificate(true);
        KeyInfoGenerator keyInfoGenerator = keyInfoGeneratorFactory.newInstance();

        Credential credential = CredentialSupport.getSimpleCredential(
            samlKeyManager.getCertificate(),
            samlKeyManager.getPrivateKey()
        );

        KeyDescriptor signKeyDescriptor = buildSAMLObject(KeyDescriptor.class, KeyDescriptor.DEFAULT_ELEMENT_NAME);
        signKeyDescriptor.setUse(UsageType.SIGNING);
        KeyInfo keyInfo = keyInfoGenerator.generate(credential);
        signKeyDescriptor.setKeyInfo(keyInfo);
        spDescriptor.getKeyDescriptors().add(signKeyDescriptor);

        KeyDescriptor encKeyDescriptor = buildSAMLObject(KeyDescriptor.class, KeyDescriptor.DEFAULT_ELEMENT_NAME);
        encKeyDescriptor.setUse(UsageType.ENCRYPTION);
        encKeyDescriptor.setKeyInfo(keyInfo);
        spDescriptor.getKeyDescriptors().add(encKeyDescriptor);

        NameIDFormat nameIDFormat = buildSAMLObject(NameIDFormat.class, NameIDFormat.DEFAULT_ELEMENT_NAME);
        nameIDFormat.setURI(NameIDType.PERSISTENT);
        spDescriptor.getNameIDFormats().add(nameIDFormat);

        AssertionConsumerService acsService = buildSAMLObject(
            AssertionConsumerService.class,
            AssertionConsumerService.DEFAULT_ELEMENT_NAME
        );
        acsService.setIndex(0);
        acsService.setIsDefault(true);
        acsService.setBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        acsService.setLocation(samlProperties.getSp().getAcsUrl());
        spDescriptor.getAssertionConsumerServices().add(acsService);

        SingleLogoutService sloService = buildSAMLObject(
            SingleLogoutService.class,
            SingleLogoutService.DEFAULT_ELEMENT_NAME
        );
        sloService.setBinding(SAMLConstants.SAML2_REDIRECT_BINDING_URI);
        sloService.setLocation(samlProperties.getSp().getSloUrl());
        spDescriptor.getSingleLogoutServices().add(sloService);

        entityDescriptor.getRoleDescriptors().add(spDescriptor);

        return marshallMetadata(entityDescriptor);
    }

    private String marshallMetadata(EntityDescriptor entityDescriptor) throws MarshallingException {
        try {
            Marshaller marshaller = XMLObjectProviderRegistrySupport.getMarshallerFactory()
                .getMarshaller(entityDescriptor);
            Element element = marshaller.marshall(entityDescriptor);

            StringWriter writer = new StringWriter();
            TransformerFactory tf = TransformerFactory.newInstance();
            Transformer transformer = tf.newTransformer();
            transformer.transform(new DOMSource(element), new StreamResult(writer));
            return writer.toString();
        } catch (Exception e) {
            throw new RuntimeException("Failed to marshall metadata", e);
        }
    }

    @SuppressWarnings("unchecked")
    private <T> T buildSAMLObject(Class<T> clazz, QName qName) {
        return (T) XMLObjectProviderRegistrySupport.getBuilderFactory()
            .getBuilder(qName)
            .buildObject(qName);
    }
}

// SamlController.java
package com.example.saml.controller;

import com.example.saml.config.SamlProperties;
import com.example.saml.security.SamlKeyManager;
import com.example.saml.service.SamlAuthenticationResult;
import com.example.saml.service.SamlMessageBuilder;
import com.example.saml.service.SamlMetadataGenerator;
import com.example.saml.service.SamlResponseProcessor;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.opensaml.messaging.context.MessageContext;
import org.opensaml.messaging.encoder.MessageEncodingException;
import org.opensaml.saml.saml2.binding.encoding.impl.HTTPRedirectDeflateEncoder;
import org.opensaml.saml.saml2.core.AuthnRequest;
import org.opensaml.saml.saml2.core.LogoutRequest;
import org.opensaml.saml.saml2.core.Response;
import org.opensaml.security.credential.Credential;
import org.opensaml.security.credential.CredentialSupport;
import org.springframework.http.MediaType;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.security.cert.X509Certificate;

@RestController
@RequestMapping("/saml")
public class SamlController {
    private final SamlMessageBuilder samlMessageBuilder;
    private final SamlResponseProcessor samlResponseProcessor;
    private final SamlMetadataGenerator samlMetadataGenerator;
    private final SamlKeyManager samlKeyManager;
    private final SamlProperties samlProperties;

    public SamlController(
        SamlMessageBuilder samlMessageBuilder,
        SamlResponseProcessor samlResponseProcessor,
        SamlMetadataGenerator samlMetadataGenerator,
        SamlKeyManager samlKeyManager,
        SamlProperties samlProperties
    ) {
        this.samlMessageBuilder = samlMessageBuilder;
        this.samlResponseProcessor = samlResponseProcessor;
        this.samlMetadataGenerator = samlMetadataGenerator;
        this.samlKeyManager = samlKeyManager;
        this.samlProperties = samlProperties;
    }

    @GetMapping("/login")
    public void initiateLogin(HttpServletRequest request, HttpServletResponse response) throws Exception {
        AuthnRequest authnRequest = samlMessageBuilder.buildAuthnRequest();
        
        request.getSession().setAttribute("authnRequestId", authnRequest.getID());

        MessageContext context = samlMessageBuilder.createMessageContext(authnRequest);
        
        HTTPRedirectDeflateEncoder encoder = new HTTPRedirectDeflateEncoder();
        encoder.setMessageContext(context);
        encoder.setHttpServletResponse(response);
        
        try {
            encoder.initialize();
            encoder.encode();
        } catch (Exception e) {
            throw new RuntimeException("Failed to encode authentication request", e);
        }
    }

    @PostMapping("/sso")
    public void processAssertion(
        @RequestParam("SAMLResponse") String samlResponse,
        HttpServletRequest request,
        HttpServletResponse response
    ) throws Exception {
        Response samlResponseObj = samlResponseProcessor.decodeResponse(samlResponse);
        
        X509Certificate certificate = samlKeyManager.getCertificate();
        Credential credential = CredentialSupport.getSimpleCredential(certificate, null);
        
        SamlAuthenticationResult result = samlResponseProcessor.processResponse(samlResponseObj, credential);
        
        HttpSession session = request.getSession();
        session.setAttribute("saml_nameId", result.getNameId());
        session.setAttribute("saml_sessionIndex", result.getSessionIndex());
        session.setAttribute("saml_attributes", result.getAttributes());
        session.setAttribute("authenticated", true);
        
        response.sendRedirect("/dashboard");
    }

    @GetMapping("/logout")
    public void initiateLogout(HttpServletRequest request, HttpServletResponse response) throws Exception {
        HttpSession session = request.getSession();
        String nameId = (String) session.getAttribute("saml_nameId");
        String sessionIndex = (String) session.getAttribute("saml_sessionIndex");
        
        if (nameId != null) {
            LogoutRequest logoutRequest = samlMessageBuilder.buildLogoutRequest(nameId, sessionIndex);
            
            MessageContext context = new MessageContext();
            context.setMessage(logoutRequest);
            
            HTTPRedirectDeflateEncoder encoder = new HTTPRedirectDeflateEncoder();
            encoder.setMessageContext(context);
            encoder.setHttpServletResponse(response);
            
            try {
                encoder.initialize();
                encoder.encode();
            } catch (Exception e) {
                throw new RuntimeException("Failed to encode logout request", e);
            }
        } else {
            session.invalidate();
            response.sendRedirect("/");
        }
    }

    @GetMapping(value = "/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    @ResponseBody
    public String metadata() throws Exception {
        return samlMetadataGenerator.generateMetadata();
    }

    @GetMapping("/status")
    @ResponseBody
    public String status(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null && Boolean.TRUE.equals(session.getAttribute("authenticated"))) {
            return "Authenticated as: " + session.getAttribute("saml_nameId");
        }
        return "Not authenticated";
    }
}

// SecurityConfiguration.java
package com.example.saml.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
@EnableWebSecurity
public class SecurityConfiguration {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .csrf(csrf -> csrf
                .ignoringRequestMatchers("/saml/**")
            )
            .authorizeHttpRequests(authz -> authz
                .requestMatchers("/saml/**").permitAll()
                .requestMatchers("/", "/login").permitAll()
                .anyRequest().authenticated()
            );
        
        return http.build();
    }
}

// DashboardController.java
package com.example.saml.controller;

import jakarta.servlet.http.HttpSession;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import java.util.List;
import java.util.Map;

@Controller
public class DashboardController {

    @GetMapping("/dashboard")
    public String dashboard(HttpSession session, Model model) {
        Boolean authenticated = (Boolean) session.getAttribute("authenticated");
        if (authenticated == null || !authenticated) {
            return "redirect:/saml/login";
        }

        String nameId = (String) session.getAttribute("saml_nameId");
        @SuppressWarnings("unchecked")
        Map<String, List<String>> attributes = (Map<String, List<String>>) session.getAttribute("saml_attributes");

        model.addAttribute("nameId", nameId);
        model.addAttribute("attributes", attributes);

        return "dashboard";
    }

    @GetMapping("/")
    public String index() {
        return "index";
    }
}